"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[54476],{55558:a=>{a.exports=JSON.parse('{"tag":{"label":"obstacle","permalink":"/dst-api-webdocs/docs/tags/obstacle","allTagsPath":"/dst-api-webdocs/docs/tags","count":12,"items":[{"id":"game-scripts/prefabs/atrium_pillar","title":"Atrium Pillar","description":"Provides a stationary physical and visual pillar obstacle in the Atrium area, with animated idle states that respond to power status.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/atrium_pillar"},{"id":"game-scripts/prefabs/crabking_icewall","title":"Crabking Icewall","description":"Creates and configures a Crabs vs. King-exclusive ice spike obstacle entity that acts as a hostile, non-healable wall with dynamic visual variation and health-based state transitions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/crabking_icewall"},{"id":"game-scripts/components/heavyobstaclephysics","title":"Heavyobstaclephysics","description":"Manages dynamic physics behavior for large in-game obstacles that transition between solid, falling, and pushed states based on proximity and interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/heavyobstaclephysics"},{"id":"game-scripts/components/heavyobstacleusetarget","title":"Heavyobstacleusetarget","description":"Controls whether an entity can interact with heavy obstacles and updates the `can_use_heavy` tag accordingly.","permalink":"/dst-api-webdocs/docs/game-scripts/components/heavyobstacleusetarget"},{"id":"game-scripts/prefabs/nightmarerock","title":"Nightmarerock","description":"A reactive environmental obstacle that physically rises or lowers based on nearby player sanity status, used in the sanity rock mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightmarerock"},{"id":"game-scripts/prefabs/quagmire_parkspike","title":"Quagmire Parkspike","description":"A static obstacle prefab used in Quagmire mode that blocks pathfinding and visual movement.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_parkspike"},{"id":"game-scripts/prefabs/quagmire_pond","title":"Quagmire Pond","description":"A static environmental object representing a salt pond in the Quagmire biome that acts as a water source and obstacle.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_pond"},{"id":"game-scripts/prefabs/rabbithouse","title":"Rabbithouse","description":"Manages a structured spawning point for Bunnymen with lighting, burnable physics, and world-state-aware door mechanics in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rabbithouse"},{"id":"game-scripts/prefabs/ruins_cavein_obstacle","title":"Ruins Cavein Obstacle","description":"Acts as a dynamic, physics-based obstacle in ruins caves that shrinks to allow character passage and falls when triggered, dealing damage or destroying nearby entities upon impact.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ruins_cavein_obstacle"},{"id":"game-scripts/prefabs/saltstack","title":"Saltstack","description":"A renewable, growable water obstacle that yields salt rocks and rock items when mined, and regrows over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/saltstack"},{"id":"game-scripts/prefabs/wagboss_robot_leg","title":"Wagboss Robot Leg","description":"Manages the landing and blocking behavior of a boss-related physics-based obstacle that reacts to environmental changes and boss presence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagboss_robot_leg"},{"id":"game-scripts/prefabs/waterplant_rock","title":"Waterplant Rock","description":"A anchored marine structure that functions as a mineable resource and upgradeable water obstacle, dropping rocks when harvested or upgraded.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waterplant_rock"}],"unlisted":false}}')}}]);